      if (totalSlides > 1) {
        if (totalEl) totalEl.textContent = totalSlides;
        if (dividerEl) dividerEl.textContent = '/';
        mainSwiper.on('slideChange', () => {
          if (currentEl) currentEl.textContent = mainSwiper.realIndex + 1;
        });
      } else {
        fractionContainer.style.display = 'none';
      }
    }

    console.log('✅ Swiper init in modal:', modal.id);
  }
})();

